// ── JUSTIFICATIVA OBRIGATÓRIA ────────────────────────────────────────────────
const TIPOS_JUSTIF_OBRIGATORIO = ['extra', 'complementar', 'reposicao', 'urgente'];

function onTipoJustChange() {
  var sel   = document.getElementById('f-tipo-justificativa');
  var lbl   = document.getElementById('lbl-justificativa');
  var inp   = document.getElementById('f-justificativa');
  if (!sel || !lbl || !inp) return;
  var val = sel.value;
  var required = TIPOS_JUSTIF_OBRIGATORIO.indexOf(val) >= 0;
  if (required) {
    lbl.innerHTML = 'Justificativa <span class="form-required">✱</span>';
    inp.placeholder = 'Obrigatório para este tipo';
    inp.setAttribute('data-required', 'true');
  } else {
    lbl.innerHTML = 'Justificativa';
    inp.placeholder = '';
    inp.removeAttribute('data-required');
  }
  // Remove any existing error highlight
  inp.style.borderColor = '';
}

function submitOrder() {
  const nome = document.getElementById('f-nome').value.trim();
  if (!nome) { alert('Preencha o nome do solicitante.'); return; }

  // Validate justificativa obrigatória
  var justifInp  = document.getElementById('f-justificativa');
  var tipoSel    = document.getElementById('f-tipo-justificativa');
  if (justifInp && tipoSel) {
    var isRequired = TIPOS_JUSTIF_OBRIGATORIO.indexOf(tipoSel.value) >= 0;
    if (isRequired && !justifInp.value.trim()) {
      justifInp.style.borderColor = '#e05252';
      justifInp.focus();
      alert('O campo Justificativa é obrigatório para o tipo selecionado.');
      return;
    }
    justifInp.style.borderColor = '';
  }
  const items = Object.values(cart);
  if (items.length === 0) return;

  const data            = document.getElementById('f-data').value;
  const prio            = document.getElementById('f-prioridade').value;
  const comprador       = document.getElementById('f-comprador').value.trim();
  const destino         = document.getElementById('f-destino').value.trim();
  const justificativa   = document.getElementById('f-justificativa').value.trim();
  const tipoJust        = document.getElementById('f-tipo-justificativa').value;
  const unidLancamento  = document.getElementById('f-unid-lancamento').value.trim();
  const unidSolicitante = document.getElementById('f-unid-solicitante').value.trim();
  const dataLancamento  = document.getElementById('f-data-lancamento').value;

  const prioLabels  = { normal:'Normal', urgente:'🔴 Urgente', baixa:'🟢 Baixa' };
  const tipoLabels  = { complementar:'Complementar', extra:'Extra', implantacao:'Implantação', mensal:'Mensal', padrao:'Padrão', reposicao:'Reposição de Estoque', urgente:'Urgente' };
  const totalQty    = items.reduce((s,i) => s + i.qty, 0);

  // Build rows safely without nested template literals
  function row(label, val) {
    if (!val) return '';
    return '<div class="modal-detail-row"><span>' + label + '</span><span>' + val + '</span></div>';
  }
  function dateStr(d) {
    try { return new Date(d + 'T12:00').toLocaleDateString('pt-BR'); } catch(e) { return d; }
  }

  const detail =
    row('Nº Pedido',        '#' + orderNum) +
    row('Unid. Lançamento', unidLancamento) +
    row('Unid. Solicitante',unidSolicitante) +
    row('Data de Lançamento', dataLancamento) +
    row('Tipo Justificativa', tipoLabels[tipoJust] || tipoJust) +
    row('Justificativa',    justificativa) +
    row('Comprador',        comprador) +
    row('Destino',          destino) +
    row('Solicitante',      nome) +
    (data ? row('Necessário até', dateStr(data)) : '') +
    row('Prioridade',       prioLabels[prio] || prio) +
    row('Itens',            items.length + ' produto(s)') +
    row('Qtd total',        totalQty + ' unidades');

  const detailEl = document.getElementById('modal-detail');
  if (detailEl) detailEl.innerHTML = detail;
  const modal = document.getElementById('modal');
  if (modal) modal.classList.add('show');
}


function closeModal() {
  document.getElementById('modal').classList.remove('show');
  // Reset
  cart = {};
  document.getElementById('f-nome').value = '';
  document.getElementById('f-comprador').value = '359915 | THAIS CAMARGO';
  document.getElementById('f-destino').value = '';
  document.getElementById('f-justificativa').value = '';
  document.getElementById('f-tipo-justificativa').value = 'padrao';
  document.getElementById('f-data').value = '';
  document.getElementById('f-prioridade').value = 'normal';
  document.getElementById('f-obs').value = '';
  document.getElementById('f-unid-lancamento').value = '';
  document.getElementById('f-unid-solicitante').value = '';
  document.getElementById('f-central-compras').value = '405 | APPA SERVICOS TEMPORARIOS-SUZ';
  Object.keys(AC_SELECTED).forEach(k => AC_SELECTED[k] = null);
  orderNum = Math.floor(100000 + Math.random() * 900000);
  document.querySelectorAll('.product-card.in-cart').forEach(c => {
    c.classList.remove('in-cart');
    const btn = c.querySelector('.add-btn');
    if (btn) { btn.classList.remove('added'); btn.textContent = '+ Adicionar'; }
  });
  updateCartUI();
}


