function acRender(key, items) {
  const dd = document.getElementById('ac-' + key);
  if (!dd) return;
  if (items.length === 0) {
    dd.innerHTML = '<div class="ac-empty">Nenhum resultado encontrado</div>';
    dd.classList.add('open');
    return;
  }
  dd.innerHTML = '';
  items.slice(0, 50).forEach(function(it) {
    const div = document.createElement('div');
    div.className = 'ac-item';
    div.innerHTML =
      '<span class="ac-item-code">' + it.codigo + '</span>' +
      '<span class="ac-item-name">' + it.nome + '</span>';
    div.addEventListener('mousedown', function(e) {
      e.preventDefault();
      acSelect(key, it.codigo, it.nome);
    });
    dd.appendChild(div);
  });
  dd.classList.add('open');
}


function acFilter(key) {
  const inp = document.getElementById('f-' + key);
  if (!inp) return;
  const q = inp.value.toLowerCase().trim();
  AC_SELECTED[key] = null; // clear selection on type
  const data = AC_DATA[key] || [];
  const filtered = q ? data.filter(it =>
    it.nome.toLowerCase().includes(q) || it.codigo.includes(q)
  ) : data;
  acRender(key, filtered.slice(0, 50));

}

function acOpen(key) {
  const data = AC_DATA[key] || [];
  const inp = document.getElementById('f-' + key);
  const q = inp ? inp.value.toLowerCase().trim() : '';
  const filtered = q ? data.filter(it =>
    it.nome.toLowerCase().includes(q) || it.codigo.includes(q)
  ) : data;
  acRender(key, filtered.slice(0, 50));
}

function acSelect(key, codigo, nome) {
  const inp = document.getElementById('f-' + key);
  if (inp) inp.value = codigo + ' | ' + nome;
  AC_SELECTED[key] = {codigo, nome};
  const dd = document.getElementById('ac-' + key);
  if (dd) dd.classList.remove('open');
  // central-compras is fixed — do not override

}

function acBlur(key) {
  setTimeout(() => {
    const dd = document.getElementById('ac-' + key);
    if (dd) dd.classList.remove('open');
    // if nothing selected and user left field partially typed, keep text
  }, 180);
}

